// Package grammar implements the BPF filter expression parser and lexer.
// The parser is generated by goyacc from grammar.y; the lexer is hand-written.
package grammar

// Token constants for the BPF filter expression lexer.
// These values must match the %token declarations in grammar.y.
// Single-character tokens (like '(', ')', '[', etc.) use their ASCII values.
// Named tokens start at 57346 (goyacc convention: yyPrivate + 1).
//
// These constants are defined manually and will be replaced by goyacc-generated
// constants once grammar.y is processed.
